(()=>{'use strict';const txt=v=>String(v??'').trim();function setText(el,v){if(el&&txt(v))el.textContent=txt(v)}function setDetail(c,v){if(!c||!txt(v))return;let p=c.querySelector('p');if(!p){p=document.createElement('p');c.prepend(p)}p.textContent=txt(v)}async function sync(){const nodes=document.querySelectorAll('[data-service-id], #servicesFeatured article[id], #servicesTrack article[id]');if(!nodes.length)return;try{const r=await fetch('/assets/data/services.json?v=admin-v2',{cache:'no-store'});if(!r.ok)throw new Error();const d=await r.json(),map=new Map((Array.isArray(d.items)?d.items:[]).map(x=>[x.id,x]));nodes.forEach(node=>{const id=node.dataset.serviceId||node.id,item=map.get(id);if(!item)return;node.hidden=item.published===false;if(item.published===false)return;setText(node.querySelector('.s-title, h3, h4'),item.title);setText(node.querySelector('.s-text, [data-cms="summary"]'),item.summary);setDetail(node.querySelector('[data-cms="detail"]'),item.detail);const link=node.querySelector('.s-link');if(link&&item.href)link.href=item.href;node.dataset.serviceTitle=item.title||node.dataset.serviceTitle||''})}catch(e){console.error('Hizmet içerikleri eşitlenemedi:',e)}}document.readyState==='loading'?document.addEventListener('DOMContentLoaded',sync):sync()})();
